```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

#include "eas_common.hpp"

using namespace sqlgen;
using namespace sqlgen::literals;

// Helper to map table_name string to model type at runtime
inline std::string normalize_table_name(const std::string& name) {
  std::string s = name;
  for (auto& c : s) c = static_cast<char>(::tolower(c));
  return s;
}

// Add records to EAS tables. T must be one of Student, Course, Score, Major.
template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  if (records.empty()) return;

  // Basic runtime check that the given table name matches T
  const std::string tname = normalize_table_name(table_name);
  const std::string type_name = normalize_table_name(rfl::name_of<T>());

  if (tname != type_name) {
    throw std::runtime_error(
        "add_eas_records: table_name '" + table_name +
        "' does not match type '" + rfl::name_of<T>() + "'");
  }

  auto conn_res = sqlgen::sqlite::connect(db_path);
  if (!conn_res) {
    throw std::runtime_error("add_eas_records: failed to connect database");
  }
  auto& conn = conn_res.value();

  sqlgen::transaction(conn).and_then([&](auto&& tx) {
    for (const auto& rec : records) {
      auto r = sqlgen::insert<T>(tx, rec);
      if (!r) {
        throw std::runtime_error("add_eas_records: insert failed");
      }
    }
    return sqlgen::commit(tx);
  }).value();
}

// Modify a record by primary key ID.
// col_name is a column of the corresponding struct and new_value is converted
// from JSON to the correct C++ type using rfl.
inline void modify_eas_records_by_id(const std::string& table_name,
                                     const std::string& record_id,
                                     const std::string& col_name,
                                     const std::string& new_value_json) {
  const std::string tname = normalize_table_name(table_name);

  auto conn_res = sqlgen::sqlite::connect(db_path);
  if (!conn_res) {
    throw std::runtime_error("modify_eas_records_by_id: failed to connect database");
  }
  auto& conn = conn_res.value();

  if (tname == "student") {
    using Model = Student;

    // Primary key is varchar, so use record_id as-is
    auto maybe_row = sqlgen::select_one<Model>(conn,
                     "WHERE SNo = ?"_sql, record_id);
    if (!maybe_row || !*maybe_row) {
      throw std::runtime_error("modify_eas_records_by_id: student not found");
    }
    Model row = **maybe_row;

    // Parse new_value_json based on column
    if (col_name == "SName") {
      row.SName = rfl::json::read<std::string>(new_value_json);
    } else if (col_name == "Sex") {
      row.Sex = rfl::json::read<int>(new_value_json);
    } else if (col_name == "Birthday") {
      // Expect ISO string, let sqlgen::DateTime be constructed from string
      auto s = rfl::json::read<std::string>(new_value_json);
      row.Birthday = sqlgen::DateTime{s};
    } else if (col_name == "Major") {
      row.Major = rfl::json::read<std::optional<uint32_t>>(new_value_json);
    } else if (col_name == "Scorses") {
      row.Scorses = rfl::json::read<std::optional<double>>(new_value_json);
    } else if (col_name == "Remark") {
      row.Remark = rfl::json::read<std::optional<std::string>>(new_value_json);
    } else {
      throw std::runtime_error("modify_eas_records_by_id: unknown column '" + col_name + "'");
    }

    sqlgen::update<Model>(conn, row).value();
    return;
  }

  if (tname == "course") {
    using Model = Course;

    uint32_t id = static_cast<uint32_t>(std::stoul(record_id));
    auto maybe_row = sqlgen::select_one<Model>(conn,
                     "WHERE CID = ?"_sql, id);
    if (!maybe_row || !*maybe_row) {
      throw std::runtime_error("modify_eas_records_by_id: course not found");
    }
    Model row = **maybe_row;

    if (col_name == "CName") {
      row.CName = rfl::json::read<std::string>(new_value_json);
    } else if (col_name == "Term") {
      row.Term = rfl::json::read<std::optional<int>>(new_value_json);
    } else if (col_name == "CTime") {
      row.CTime = rfl::json::read<std::optional<int>>(new_value_json);
    } else if (col_name == "Credit") {
      row.Credit = rfl::json::read<int>(new_value_json);
    } else {
      throw std::runtime_error("modify_eas_records_by_id: unknown column '" + col_name + "'");
    }

    sqlgen::update<Model>(conn, row).value();
    return;
  }

  if (tname == "score") {
    using Model = Score;

    uint32_t id = static_cast<uint32_t>(std::stoul(record_id));
    auto maybe_row = sqlgen::select_one<Model>(conn,
                     "WHERE ScID = ?"_sql, id);
    if (!maybe_row || !*maybe_row) {
      throw std::runtime_error("modify_eas_records_by_id: score not found");
    }
    Model row = **maybe_row;

    if (col_name == "SNo") {
      auto s = rfl::json::read<std::string>(new_value_json);
      row.SNo = s;
    } else if (col_name == "CID") {
      auto cid = rfl::json::read<uint32_t>(new_value_json);
      row.CID = cid;
    } else if (col_name == "Score") {
      row.Score = rfl::json::read<std::optional<double>>(new_value_json);
    } else {
      throw std::runtime_error("modify_eas_records_by_id: unknown column '" + col_name + "'");
    }

    sqlgen::update<Model>(conn, row).value();
    return;
  }

  if (tname == "major") {
    using Model = Major;

    uint32_t id = static_cast<uint32_t>(std::stoul(record_id));
    auto maybe_row = sqlgen::select_one<Model>(conn,
                     "WHERE MID = ?"_sql, id);
    if (!maybe_row || !*maybe_row) {
      throw std::runtime_error("modify_eas_records_by_id: major not found");
    }
    Model row = **maybe_row;

    if (col_name == "MName") {
      row.MName = rfl::json::read<std::string>(new_value_json);
    } else {
      throw std::runtime_error("modify_eas_records_by_id: unknown column '" + col_name + "'");
    }

    sqlgen::update<Model>(conn, row).value();
    return;
  }

  throw std::runtime_error("modify_eas_records_by_id: unknown table '" + table_name + "'");
}

// Delete a record by primary key ID.
// record_id is passed as string and converted based on table.
inline void delete_eas_records_by_id(const std::string& table_name,
                                     const std::string& record_id) {
  const std::string tname = normalize_table_name(table_name);

  auto conn_res = sqlgen::sqlite::connect(db_path);
  if (!conn_res) {
    throw std::runtime_error("delete_eas_records_by_id: failed to connect database");
  }
  auto& conn = conn_res.value();

  if (tname == "student") {
    // PK is varchar
    sqlgen::exec(conn,
      "DELETE FROM Student WHERE SNo = ?;"_sql, record_id).value();
    return;
  }

  if (tname == "course") {
    uint32_t id = static_cast<uint32_t>(std::stoul(record_id));
    sqlgen::exec(conn,
      "DELETE FROM Course WHERE CID = ?;"_sql, id).value();
    return;
  }

  if (tname == "score") {
    uint32_t id = static_cast<uint32_t>(std::stoul(record_id));
    sqlgen::exec(conn,
      "DELETE FROM Score WHERE ScID = ?;"_sql, id).value();
    return;
  }

  if (tname == "major") {
    uint32_t id = static_cast<uint32_t>(std::stoul(record_id));
    sqlgen::exec(conn,
      "DELETE FROM Major WHERE MID = ?;"_sql, id).value();
    return;
  }

  throw std::runtime_error("delete_eas_records_by_id: unknown table '" + table_name + "'");
}
