#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace delete_inactive_users {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::optional<sqlgen::DateTime> last_login;
  std::string status = "active";
};

int delete_inactive_users() {
  // Connect to the SQLite database "test_db.sqlite"
  sqlgen::sqlite::Database db("test_db.sqlite");

  // Build ORM for the User table
  auto orm = sqlgen::make_orm<User>(db, "User");

  // Start a transaction to ensure safety
  sqlgen::Transaction tx(db);

  // Condition: delete users whose last_login is before 2025-01-01
  // Reference SQL:
