  int deleted_rows = orm.remove_where(
      sqlgen::less_than(&User::last_login, sqlgen::DateTime("2025-01-01 00:00:00"))
  );

  // Commit the transaction and return the result of the commit operation.
  // Assuming commit() returns an int-like status or number of changes.
  tx.commit();

  return deleted_rows;
}

} // namespace delete_inactive_users
