 * - Insert related data
 * - Call query_customer_purchase_history
 * - Verify correct products and dates
 */
TEST(sqlite, query_customer_purchase_history) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Cleanup
  auto conn = sqlite::connect("test_db.sqlite").value();
  drop<OrderItem>(conn);
  drop<Order>(conn);
  drop<Product>(conn);
  drop<Customer>(conn);

  // 1. Create tables and insert data
  create_table<Customer>(conn);
  create_table<Product>(conn);
  create_table<Order>(conn);
  create_table<OrderItem>(conn);

  Customer c1{.customer_id = 1, .name = "Alice", .email = "alice@example.com"};
  Customer c2{.customer_id = 2, .name = "Bob", .email = "bob@example.com"};
  insert(conn, std::vector{c1, c2});

  Product p1{.product_id = 1, .name = "Laptop", .price = 1000.0};
  Product p2{.product_id = 2, .name = "Mouse", .price = 20.0};
  insert(conn, std::vector{p1, p2});

  // Alice's orders
  // Order 1: 2023-01-01, 1 Laptop
  Order o1{.order_id = 1, .customer_id = 1, .order_date = "2023-01-01 10:00:00"};
  // Order 2: 2023-02-01, 2 Mice
  Order o2{.order_id = 2, .customer_id = 1, .order_date = "2023-02-01 15:00:00"};
  insert(conn, std::vector{o1, o2});

  OrderItem oi1{.item_id = 1, .order_id = 1, .product_id = 1, .quantity = 1};
  OrderItem oi2{.item_id = 2, .order_id = 2, .product_id = 2, .quantity = 2};
  insert(conn, std::vector{oi1, oi2});

  // 2. Call query function for Alice
  auto history = query_customer_purchase_history(1);

  // 3. Verify results
  // Expected order: Order 2 (Mouse) then Order 1 (Laptop) due to DESC date
  ASSERT_EQ(history.size(), 2);

  EXPECT_EQ(history[0].product_name, "Mouse");
  EXPECT_EQ(history[0].quantity, 2);
  // Verify date string contains correct date part
  EXPECT_TRUE(history[0].order_date.str().starts_with("2023-02-01"));

  EXPECT_EQ(history[1].product_name, "Laptop");
  EXPECT_EQ(history[1].quantity, 1);
  EXPECT_TRUE(history[1].order_date.str().starts_with("2023-01-01"));
}

