  //
  // We will select Product, Order and OrderItem rows and then map them into
  // PurchaseHistory results in C++.
  std::vector<PurchaseHistory> result;

  auto q = query<Product, Order, OrderItem>(db)
             .join<Customer>(
                 // join Order to Customer on customer_id
                 on(&Order::customer_id == &Customer::customer_id))
             .join<Order>(
