};

struct BookFilters {
  std::optional<std::string> title_keyword;
  std::optional<int> min_year;
  std::optional<std::string> genre;
  std::optional<double> max_price;
};

/**
 * Function: Search for books based on multiple optional criteria.
 * 
 * @param filters Optional filters for title, year, genre, and price
 * @return List of books matching the criteria
 */
std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
  // Open a connection to the SQLite database "test_db.sqlite"
  sqlgen::sqlite::Connection conn("test_db.sqlite");

  // Register mapping for Book with sqlgen
  sqlgen::Mapper<Book> mapper(conn);

  // Start with a base SELECT query: SELECT * FROM Book
  auto q = mapper.select();

  // Collect optional WHERE clauses based on provided filters

  // Title: use LIKE with wildcards around the keyword
  if (filters.title_keyword.has_value()) {
    // Wrap the keyword with '%' for substring search
    std::string pattern = "%" + *filters.title_keyword + "%";
    q = q.where(&Book::title, sqlgen::Op::Like, pattern);
  }

  // Minimum publication year: year >= min_year
  if (filters.min_year.has_value()) {
    q = q.where(&Book::year, sqlgen::Op::Ge, *filters.min_year);
  }

  // Genre: exact match
  if (filters.genre.has_value()) {
    q = q.where(&Book::genre, sqlgen::Op::Eq, *filters.genre);
  }

  // Maximum price: price <= max_price
  if (filters.max_price.has_value()) {
    q = q.where(&Book::price, sqlgen::Op::Le, *filters.max_price);
  }

  // Execute the query and return the resulting books
  return q.all();
}

}  // namespace query_search_books_by_criteria
