#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <string>

namespace soft_delete_records {

struct Document {
  sqlgen::PrimaryKey<int> doc_id;
  std::string title;
  int is_deleted = 0;
  std::optional<sqlgen::DateTime> deleted_at;
};

// Function to perform a soft delete on documents with the given IDs.
// Returns true on success, false if an exception occurs.
bool soft_delete_records(const std::vector<int>& ids) {
    if (ids.empty()) {
        // Nothing to delete; treat as success.
        return true;
    }

    try {
        // Open SQLite database connection.
        sqlgen::sqlite::Database db("test_db.sqlite");

        // Create a model bound to the Document table.
        // Assuming the table name in the DB is exactly "Document".
        auto model = sqlgen::make_model<Document>(db, "Document");

        // Start a transaction so all updates succeed or fail together.
        auto tx = db.transaction();

        // Current timestamp from sqlgen.
        auto now = sqlgen::DateTime::now();

        // Update each document in turn.
        for (int id : ids) {
            // Build a partial Document with only the fields we want to update.
            Document doc;
            doc.doc_id = id;
            doc.is_deleted = 1;
            doc.deleted_at = now;

            // Update the row with matching primary key.
            // This will generate an UPDATE with WHERE doc_id = ?
            model.update(doc);
        }

        // Commit transaction.
        tx.commit();
        return true;
    } catch (const std::exception&) {
        // In a real application, you'd likely log the error.
        return false;
    }
}

}  // namespace soft_delete_records
