#include <stdexcept>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  // Guard against nonsensical transfers
  if (amount <= 0.0) {
    return false;
  }

  // Open connection to SQLite database
  sqlgen::sqlite::connection conn("test_db.sqlite");

  // Wrap operations in a transaction
  sqlgen::transaction tx(conn);

  try {
    // Load the sender (from_account)
    auto from_opt = sqlgen::get<Account>(conn, from_account_id);
    if (!from_opt) {
      tx.rollback();
      return false;  // sender account doesn't exist
    }
    Account from = *from_opt;

    // Load the receiver (to_account)
    auto to_opt = sqlgen::get<Account>(conn, to_account_id);
    if (!to_opt) {
      tx.rollback();
      return false;  // receiver account doesn't exist
    }
    Account to = *to_opt;

    // Check sufficient funds
    if (from.balance < amount) {
      tx.rollback();
      return false;
    }

    // Perform the updates in memory
    from.balance -= amount;
    to.balance += amount;

    // Persist the updates
    sqlgen::update(conn, from);
    sqlgen::update(conn, to);

    // Commit the transaction
    tx.commit();
    return true;
