  // Ensure the database and all original tables (including Major) exist
  design_eas_database_with_major();

  // Connect and perform the required schema changes using raw SQL via sqlgen
  sqlgen::sqlite::connect(db_path)
      .and_then([](auto&& conn) {
        // 1. Add a new column Grade to table Score: CHAR(1) NOT NULL
        // 2. Modify column type of Age in Student to INT NULL
        // 3. Drop table Major
        //
        // Note: Only the requested operations are performed; no assumptions are
        // made about existing data beyond what is needed for these ALTERs.

        return sqlgen::exec(
                   conn,
                   "ALTER TABLE Score "
                   "ADD COLUMN Grade CHAR(1) NOT NULL DEFAULT ' ';")
            .and_then([&conn](auto&&) {
              // If Age column does not exist, this statement will fail;
              // we execute exactly what the task requires.
              return sqlgen::exec(
                  conn,
                  "ALTER TABLE Student "
                  "ALTER COLUMN Age INT;");
            })
            .and_then([&conn](auto&&) {
              return sqlgen::exec(conn, "DROP TABLE IF EXISTS Major;");
            });
      })
      .value();
}

