  // Mark this type as a view for sqlgen
  static constexpr bool is_view = true;

  std::string product_name;
  int total_quantity;
  double total_revenue;
};

/**
 * Function: Create a view SalesSummary that aggregates sales by product.
 * 
 * @return true if view creation succeeds, false otherwise
 */
bool create_view_sales_summary() {
  using namespace sqlgen;

  try {
    // Open / create SQLite database "test_db.sqlite"
    sqlite::connection db{"test_db.sqlite"};

    // Manually drop the view if it exists (SQLite has limited IF NOT EXISTS support)
    {
      statement drop_stmt{
          db,
          "DROP VIEW IF EXISTS SalesSummary;"  // Safe even if the view does not exist
      };
      drop_stmt.exec();
    }

    // Build the SELECT query that defines the view using sqlgen
    //
    // Equivalent SQL:
    // SELECT p.name AS product_name,
    //        SUM(s.quantity) AS total_quantity,
    //        SUM(s.amount)   AS total_revenue
    // FROM Sale s
    // JOIN Product p ON s.product_id = p.product_id
    // GROUP BY p.name;
    auto query = select(
                     Product{}.name.as(alias{"product_name"}),
                     sum(Sale{}.quantity).as(alias{"total_quantity"}),
                     sum(Sale{}.amount).as(alias{"total_revenue"}))
                     .from(Sale{})
                     .join(Product{},
                           on(Sale{}.product_id == Product{}.product_id))
                     .group_by(Product{}.name);

    // Generate the CREATE VIEW statement using sqlgen
    //
    // Depending on the exact sqlgen API, this is typically done with
    // create_view<T>(connection, name, select_query) or create_as.
    // We'll use create_view specialized with the SalesSummary view type.
    auto create_view_sql = sqlite::create_view<SalesSummary>(
        "SalesSummary",  // view name
        query            // defining SELECT query
    );

    // Execute the CREATE VIEW statement
    {
      statement create_stmt{db, create_view_sql};
      create_stmt.exec();
    }

    return true;
  } catch (const std::exception&) {
    // Any error (connection, SQL, etc.) -> signal failure
    return false;
  }
