```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace right_join_departments_projects {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string name;
};

struct Project {
  sqlgen::PrimaryKey<int> project_id;
  int department_id;
  std::string name;
};

struct DepProj {
  // Department name is optional because we conceptually
  // allow projects without a matching department.
  std::optional<std::string> department_name;
  std::string project_name;
};

/**
 * description: right_join_departments_projects.
 * This function demonstrates how to perform a right join between departments and projects using sqlgen read API.
 * It returns a vector of DepProj structs, where each struct contains the department name (if available) and the project name.
 * Returns: std::vector<DepProj>.
 */
std::vector<DepProj> right_join_departments_projects() {
  using namespace sqlgen;

  // Connect to the SQLite database "test_db.sqlite"
  sqlite::Database db("test_db.sqlite");

  //
  // SQLite does not support RIGHT JOIN directly.
  // RIGHT JOIN Department ON Project.department_id = Department.department_id
  // is equivalent to:
  //
  //   SELECT ...
  //   FROM Department
  //   LEFT JOIN Project
  //     ON Department.department_id = Project.department_id;
  //
  // We want to "include all departments", i.e. departments without projects.
  //

  // Build a LEFT JOIN query (Department LEFT JOIN Project)
  auto query = db.read<Department, Project>()
                 .left_join<Project>(
                     &Department::department_id,
                     &Project::department_id
                 );

  // Execute the query, which returns a list of tuples (Department, Project)
  auto rows = query.exec();

  std::vector<DepProj> result;
  result.reserve(rows.size());

  for (auto &row : rows) {
    Department dept;
    Project proj;

    // unpack the tuple/aggregate returned by sqlgen
    std::tie(dept, proj) = row;

    DepProj dp;

    // Department is always present in this LEFT JOIN, so name is non-null
    dp.department_name = dept.name;

    // Project may or may not exist; sqlgen represents "no match" by
    // default-constructed object. We treat an empty project name as "no project".
    if (!proj.name.empty()) {
      dp.project_name = proj.name;
    } else {
      dp.project_name = "";
    }

    result.push_back(std::move(dp));
  }

  return result;
}

}  // namespace right_join_departments_projects
```

