  using namespace sqlgen::sqlite;

  // Register models with the SQLite backend (no execution, just metadata)
  auto db = database("test_db.sqlite");
  db.attach<A>("A");
  db.attach<B>("B");

  // Build a complex query:
  // SELECT A.id, A.name, B.score
  // FROM A
  // INNER JOIN B ON A.id = B.a_id
  // WHERE B.score > 10 AND A.name LIKE '%x%'
  // ORDER BY B.score DESC, A.name ASC
  // LIMIT 50;
  auto q = db.select(&A::id, &A::name, &B::score)
      .from<A>()
      .join<B>(on(&A::id == &B::a_id))
      .where(
          &B::score > 10.0 &&
          like(&A::name, "%x%")
      )
      .order_by(desc(&B::score), asc(&A::name))
      .limit(50);

  // Generate SQL without executing (dry run)
  std::string sql = to_sql(q);

  // Basic verification that the generated SQL contains expected clauses.
  // This is only a sanity check; it does not attempt full SQL parsing.
  if (sql.find("JOIN") == std::string::npos &&
      sql.find("join") == std::string::npos) {
    throw std::runtime_error("Generated SQL is missing JOIN clause");
