```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <cstdint>
#include <string>

namespace analyze_temporal_data {

struct Event {
  sqlgen::PrimaryKey<int> event_id;
  std::string event_name;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> start_time;
  std::optional<sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S">> end_time;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct TemporalAnalysis {
  int event_id;
  std::string event_name;
  int start_day;
  int start_month;
  int start_year;
  int start_hour;
  int start_minute;
  int start_second;
  int start_weekday;
  int64_t start_epoch;
  std::optional<double> duration_days;
};

/**
 * @brief Analyze temporal data for a collection of events.
 *
 * Inserts the provided events into the SQLite Event table in "test_db.sqlite",
 * runs a query to extract date/time parts and compute duration, and returns
 * the results as a vector of TemporalAnalysis.
 *
 * Notes on SQLite date/time functions used:
 *  - strftime('%d', ts) -> day (01-31)
 *  - strftime('%m', ts) -> month (01-12)
 *  - strftime('%Y', ts) -> year (0000-9999)
 *  - strftime('%H', ts) -> hour (00-24)
 *  - strftime('%M', ts) -> minute (00-59)
 *  - strftime('%S', ts) -> second (00-59)
 *  - strftime('%w', ts) -> weekday (0‑6, 0 = Sunday)
 *  - unixepoch(ts)      -> seconds since Unix epoch
 *
 * Duration (days) is computed as: (unixepoch(end_time) - unixepoch(start_time)) / 86400.0
 *
 * @param events Vector of Event records to analyze.
 * @return std::vector<TemporalAnalysis> Analysis results for each event that has an end_time.
 */
std::vector<TemporalAnalysis> analyze_temporal_data (const std::vector<Event>& events)  {
  using namespace sqlgen;

  // Open (or create) the SQLite database "test_db.sqlite"
  sqlite::Database db("test_db.sqlite");

  // Create the Event table if it does not exist.
  // This matches the schema described in the prompt.
  {
    auto create_stmt = db.prepare(R"SQL(
      CREATE TABLE IF NOT EXISTS Event (
        event_id    INTEGER PRIMARY KEY,
        event_name  TEXT NOT NULL,
        start_time  TEXT NOT NULL,
        end_time    TEXT,
        created_at  TEXT NOT NULL
      );
    )SQL");
    create_stmt.execute();
  }

  // Use sqlgen to map the Event struct to the Event table.
  // The mapping is idempotent; calling it multiple times is safe.
  auto mapping = make_table<Event>(
      "Event",
      &Event::event_id,
      &Event::event_name,
      &Event::start_time,
      &Event::end_time,
      &Event::created_at
  );

  // Insert the provided events into the Event table.
  // Use a transaction for efficiency.
  {
    sqlite::Transaction txn(db);
    for (const auto& ev : events) {
      mapping.insert(db, ev);
    }
    txn.commit();
  }

  // Prepare the temporal analysis query using SQLite-compatible functions.
  //
  // Reference SQL (adapted for SQLite):
  // SELECT
  //   event_id,
  //   event_name,
  //   CAST(strftime('%d', start_time) AS INTEGER) AS start_day,
  //   CAST(strftime('%m', start_time) AS INTEGER) AS start_month,
  //   CAST(strftime('%Y', start_time) AS INTEGER) AS start_year,
  //   CAST(strftime('%H', start_time) AS INTEGER) AS start_hour,
  //   CAST(strftime('%M', start_time) AS INTEGER) AS start_minute,
  //   CAST(strftime('%S', start_time) AS INTEGER) AS start_second,
  //   CAST(strftime('%w', start_time) AS INTEGER) AS start_weekday,
  //   CAST(unixepoch(start_time) AS INTEGER)      AS start_epoch,
  //   (unixepoch(end_time) - unixepoch(start_time)) / 86400.0 AS duration_days
  // FROM Event
  // WHERE end_time IS NOT NULL;
  auto stmt = db.prepare(R"SQL(
    SELECT
      event_id,
      event_name,
      CAST(strftime('%d', start_time) AS INTEGER) AS start_day,
      CAST(strftime('%m', start_time) AS INTEGER) AS start_month,
      CAST(strftime('%Y', start_time) AS INTEGER) AS start_year,
      CAST(strftime('%H', start_time) AS INTEGER) AS start_hour,
      CAST(strftime('%M', start_time) AS INTEGER) AS start_minute,
      CAST(strftime('%S', start_time) AS INTEGER) AS start_second,
      CAST(strftime('%w', start_time) AS INTEGER) AS start_weekday,
      CAST(unixepoch(start_time) AS INTEGER)      AS start_epoch,
      (unixepoch(end_time) - unixepoch(start_time)) / 86400.0 AS duration_days
