/**
 * @brief Analyze temporal data for a collection of events.
 *
 * Inserts the provided events into the SQLite Event table in "test_db.sqlite",
 * runs a query to extract date/time parts and compute duration, and returns
 * the results as a vector of TemporalAnalysis.
 *
 * Notes on SQLite date/time functions used:
 *  - strftime('%d', ts) -> day (01-31)
 *  - strftime('%m', ts) -> month (01-12)
 *  - strftime('%Y', ts) -> year (0000-9999)
 *  - strftime('%H', ts) -> hour (00-24)
 *  - strftime('%M', ts) -> minute (00-59)
 *  - strftime('%S', ts) -> second (00-59)
 *  - strftime('%w', ts) -> weekday (0‑6, 0 = Sunday)
 *  - unixepoch(ts)      -> seconds since Unix epoch
 *
 * Duration (days) is computed as: (unixepoch(end_time) - unixepoch(start_time)) / 86400.0
 *
 * @param events Vector of Event records to analyze.
 * @return std::vector<TemporalAnalysis> Analysis results for each event that has an end_time.
 */
std::vector<TemporalAnalysis> analyze_temporal_data (const std::vector<Event>& events)  {
