  // Open (or create) the SQLite database "test_db.sqlite"
  sqlite::Database db("test_db.sqlite");

  // Create the Event table if it does not exist.
  // This matches the schema described in the prompt.
  {
    auto create_stmt = db.prepare(R"SQL(
      CREATE TABLE IF NOT EXISTS Event (
        event_id    INTEGER PRIMARY KEY,
        event_name  TEXT NOT NULL,
        start_time  TEXT NOT NULL,
        end_time    TEXT,
        created_at  TEXT NOT NULL
      );
    )SQL");
    create_stmt.execute();
