  // The mapping is idempotent; calling it multiple times is safe.
  auto mapping = make_table<Event>(
      "Event",
      &Event::event_id,
      &Event::event_name,
      &Event::start_time,
      &Event::end_time,
      &Event::created_at
  );

  // Insert the provided events into the Event table.
  // Use a transaction for efficiency.
  {
    sqlite::Transaction txn(db);
    for (const auto& ev : events) {
      mapping.insert(db, ev);
    }
    txn.commit();
  }

  // Prepare the temporal analysis query using SQLite-compatible functions.
  //
  // Reference SQL (adapted for SQLite):
  // SELECT
  //   event_id,
  //   event_name,
  //   CAST(strftime('%d', start_time) AS INTEGER) AS start_day,
  //   CAST(strftime('%m', start_time) AS INTEGER) AS start_month,
  //   CAST(strftime('%Y', start_time) AS INTEGER) AS start_year,
  //   CAST(strftime('%H', start_time) AS INTEGER) AS start_hour,
  //   CAST(strftime('%M', start_time) AS INTEGER) AS start_minute,
  //   CAST(strftime('%S', start_time) AS INTEGER) AS start_second,
  //   CAST(strftime('%w', start_time) AS INTEGER) AS start_weekday,
  //   CAST(unixepoch(start_time) AS INTEGER)      AS start_epoch,
  //   (unixepoch(end_time) - unixepoch(start_time)) / 86400.0 AS duration_days
  // FROM Event
  // WHERE end_time IS NOT NULL;
  auto stmt = db.prepare(R"SQL(
    SELECT
      event_id,
      event_name,
      CAST(strftime('%d', start_time) AS INTEGER) AS start_day,
      CAST(strftime('%m', start_time) AS INTEGER) AS start_month,
      CAST(strftime('%Y', start_time) AS INTEGER) AS start_year,
      CAST(strftime('%H', start_time) AS INTEGER) AS start_hour,
      CAST(strftime('%M', start_time) AS INTEGER) AS start_minute,
      CAST(strftime('%S', start_time) AS INTEGER) AS start_second,
      CAST(strftime('%w', start_time) AS INTEGER) AS start_weekday,
      CAST(unixepoch(start_time) AS INTEGER)      AS start_epoch,
      (unixepoch(end_time) - unixepoch(start_time)) / 86400.0 AS duration_days
    FROM Event
    WHERE end_time IS NOT NULL;
  )SQL");

  std::vector<TemporalAnalysis> results;
  while (stmt.step()) {
    TemporalAnalysis ta{};
    int col = 0;

    ta.event_id      = stmt.column_int(col++);
    ta.event_name    = stmt.column_text(col++);
