#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <iostream>
#include <string>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

/**
 * Analyze social network data by creating SQL tables for User and Friendship.
 * Returns: std::vector<FriendConnection>.
 *
 * This function:
 * 1. Connects to SQLite DB "test_db.sqlite"
 * 2. Creates User and Friendship tables with schema close to the spec
 * 3. Inserts provided users and friendships
 * 4. Runs:
 *    - mutual-friends self-join query
 *    - nested query for users with more than N friends
 *    - friend-of-friend (exactly one mutual friend)
 *    - aggregation of friends per user
 *    - same-city non-friends recommendation
 *
 * The return value is based on the mutual-friends query (u1,u2 pairs).
 */
std::vector<FriendConnection> analyze_social_network_impl(
    const std::vector<User>& users,
    const std::vector<Friendship>& friendships) {

  using namespace sqlgen;

  // Connect to SQLite database "test_db.sqlite"
  sqlite::Connection conn("test_db.sqlite");

  // Create tables (drop if they already exist to get a clean run)
  conn.execute(R"SQL(
    DROP TABLE IF EXISTS Friendship;
  )SQL");

  conn.execute(R"SQL(
    DROP TABLE IF EXISTS User;
  )SQL");

  // User table according to spec (adding minimal columns needed for queries;
  // some columns are stubbed with defaults since they are not provided in input).
  conn.execute(R"SQL(
    CREATE TABLE IF NOT EXISTS User (
      user_id     INTEGER PRIMARY KEY,
      username    VARCHAR(50) NOT NULL UNIQUE,
      email       VARCHAR(100) NOT NULL UNIQUE,
      join_date   DATETIME NOT NULL,
      city        VARCHAR(50)
    );
  )SQL");

  // Friendship table according to spec
  conn.execute(R"SQL(
    CREATE TABLE IF NOT EXISTS Friendship (
      user_id1        INTEGER NOT NULL,
      user_id2        INTEGER NOT NULL,
      friendship_date DATETIME NOT NULL,
      PRIMARY KEY (user_id1, user_id2),
      FOREIGN KEY (user_id1) REFERENCES User(user_id),
      FOREIGN KEY (user_id2) REFERENCES User(user_id)
    );
  )SQL");

  // Insert data into User
  {
    sqlite::Statement stmt(conn,
      "INSERT INTO User (user_id, username, email, join_date, city) "
      "VALUES (?, ?, ?, datetime('now'), NULL);");

    for (const auto& u : users) {
      stmt.reset();
      stmt.bind(1, u.user_id.value());
      stmt.bind(2, u.username);
      // simple synthetic email just to satisfy NOT NULL UNIQUE
      stmt.bind(3, u.username + "@example.com");
      stmt.step();
    }
  }

  // Insert data into Friendship (ensure symmetric storage if desired;
  // here we store exactly what is given).
  {
    sqlite::Statement stmt(conn,
      "INSERT OR IGNORE INTO Friendship (user_id1, user_id2, friendship_date) "
      "VALUES (?, ?, ?);");

    for (const auto& f : friendships) {
      stmt.reset();
      stmt.bind(1, f.user1_id);
      stmt.bind(2, f.user2_id);
      stmt.bind(3, f.created_at.to_string());
      stmt.step();
    }
  }

  // 1) Use SELF-JOIN to find mutual friends (friends who share the same friend)
  // The following query is adapted from the reference SQL. It finds user pairs
  // that share at least one mutual friend and are already friends.
  std::vector<FriendConnection> result;

  {
    const char* sql = R"SQL(
      SELECT u1.username AS user1_name,
             u2.username AS user2_name,
             COUNT(f1.user_id2) AS mutual_friends
      FROM User u1
      INNER JOIN Friendship f1 ON u1.user_id = f1.user_id1
      INNER JOIN Friendship f2 ON f1.user_id2 = f2.user_id1
      INNER JOIN User u2 ON f2.user_id2 = u2.user_id
      WHERE u1.user_id < u2.user_id
        AND EXISTS (
          SELECT 1 FROM Friendship f3
          WHERE (f3.user_id1 = u1.user_id AND f3.user_id2 = u2.user_id)
             OR (f3.user_id1 = u2.user_id AND f3.user_id2 = u1.user_id)
        )
      GROUP BY u1.user_id, u2.user_id
      HAVING COUNT(f1.user_id2) > 0;
    )SQL";

    sqlite::Statement stmt(conn, sql);
    while (stmt.step() == SQLITE_ROW) {
      FriendConnection fc;
      fc.user1_name = stmt.column_text(0);
      fc.user2_name = stmt.column_text(1);
      // mutual_friends count is available at column 2 if needed
      result.push_back(fc);
    }
  }

  // 2) Nested query: find users with more than N friends (N derived using a subquery).
  {
    const char* sql = R"SQL(
      SELECT u.user_id,
             u.username,
             COUNT(f.user_id2) AS friend_count
      FROM User u
      LEFT JOIN Friendship f ON u.user_id = f.user_id1
      GROUP BY u.user_id, u.username
      HAVING friend_count > (
        SELECT AVG(friend_count)
        FROM (
          SELECT COUNT(*) AS friend_count
          FROM Friendship
          GROUP BY user_id1
        )
      )
      ORDER BY friend_count DESC;
    )SQL";

    sqlite::Statement stmt(conn, sql);
    while (stmt.step() == SQLITE_ROW) {
      // Consume rows to exercise the nested query; not returned from function
      int user_id = stmt.column_int(0);
      std::string username = stmt.column_text(1);
      int friend_count = stmt.column_int(2);
      (void)user_id;
      (void)username;
      (void)friend_count;
    }
  }

  // 3) Friend-of-friend relationships (people connected through exactly one mutual friend)
  // We find pairs that are not already friends but share exactly one mutual friend.
  {
    const char* sql = R"SQL(
      SELECT DISTINCT
             u1.username AS user1_name,
             u2.username AS user2_name,
             COUNT(DISTINCT f1.user_id2) AS mutual_count
      FROM User u1
      JOIN Friendship f1 ON u1.user_id = f1.user_id1
      JOIN Friendship f2 ON f1.user_id2 = f2.user_id1
      JOIN User u2 ON f2.user_id2 = u2.user_id
      WHERE u1.user_id < u2.user_id
        -- not already friends (in either direction)
        AND NOT EXISTS (
          SELECT 1 FROM Friendship f3
          WHERE (f3.user_id1 = u1.user_id AND f3.user_id2 = u2.user_id)
             OR (f3.user_id1 = u2.user_id AND f3.user_id2 = u1.user_id)
        )
      GROUP BY u1.user_id, u2.user_id
      HAVING COUNT(DISTINCT f1.user_id2) = 1;
    )SQL";

    sqlite::Statement stmt(conn, sql);
    while (stmt.step() == SQLITE_ROW) {
      // again, only to demonstrate query execution
      std::string u1 = stmt.column_text(0);
      std::string u2 = stmt.column_text(1);
      int mutual_count = stmt.column_int(2);
      (void)u1;
      (void)u2;
      (void)mutual_count;
    }
  }

  // 4) Count friends per user and identify most connected users (aggregation).
  {
    const char* sql = R"SQL(
      SELECT u.user_id,
             u.username,
             COUNT(f.user_id2) AS friend_count
      FROM User u
      LEFT JOIN Friendship f ON u.user_id = f.user_id1
      GROUP BY u.user_id, u.username
      ORDER BY friend_count DESC, u.user_id ASC;
    )SQL";

    sqlite::Statement stmt(conn, sql);
    while (stmt.step() == SQLITE_ROW) {
      int user_id = stmt.column_int(0);
      std::string username = stmt.column_text(1);
      int friend_count = stmt.column_int(2);
      (void)user_id;
      (void)username;
      (void)friend_count;
    }
  }

  // 5) Users in the same city who are not yet friends (recommendation).
  // For this example, all cities are NULL unless the database was pre-populated
  // with additional data, but the query structure demonstrates the pattern.
  {
    const char* sql = R"SQL(
      SELECT u1.username AS user1_name,
             u2.username AS user2_name,
             u1.city
      FROM User u1
      JOIN User u2
        ON u1.city IS NOT NULL
       AND u1.city = u2.city
       AND u1.user_id < u2.user_id
      WHERE NOT EXISTS (
        SELECT 1 FROM Friendship f
        WHERE (f.user_id1 = u1.user_id AND f.user_id2 = u2.user_id)
           OR (f.user_id1 = u2.user_id AND f.user_id2 = u1.user_id)
      );
    )SQL";

    sqlite::Statement stmt(conn, sql);
    while (stmt.step() == SQLITE_ROW) {
      std::string u1 = stmt.column_text(0);
      std::string u2 = stmt.column_text(1);
      std::string city = stmt.column_text(2);
      (void)u1;
      (void)u2;
      (void)city;
    }
  }

  // Return mutual-friend connections as the main analysis result
  return result;
}

}  // namespace analyze_social_network
