      // mutual_friends count is available at column 2 if needed
      result.push_back(fc);
    }
  }

  // 2) Nested query: find users with more than N friends (N derived using a subquery).
  {
    const char* sql = R"SQL(
      SELECT u.user_id,
             u.username,
             COUNT(f.user_id2) AS friend_count
      FROM User u
      LEFT JOIN Friendship f ON u.user_id = f.user_id1
      GROUP BY u.user_id, u.username
      HAVING friend_count > (
        SELECT AVG(friend_count)
        FROM (
          SELECT COUNT(*) AS friend_count
          FROM Friendship
          GROUP BY user_id1
        )
      )
      ORDER BY friend_count DESC;
    )SQL";

    sqlite::Statement stmt(conn, sql);
    while (stmt.step() == SQLITE_ROW) {
      // Consume rows to exercise the nested query; not returned from function
      int user_id = stmt.column_int(0);
      std::string username = stmt.column_text(1);
      int friend_count = stmt.column_int(2);
      (void)user_id;
      (void)username;
      (void)friend_count;
    }
  }

  // 3) Friend-of-friend relationships (people connected through exactly one mutual friend)
  // We find pairs that are not already friends but share exactly one mutual friend.
  {
    const char* sql = R"SQL(
      SELECT DISTINCT
             u1.username AS user1_name,
             u2.username AS user2_name,
             COUNT(DISTINCT f1.user_id2) AS mutual_count
      FROM User u1
      JOIN Friendship f1 ON u1.user_id = f1.user_id1
      JOIN Friendship f2 ON f1.user_id2 = f2.user_id1
      JOIN User u2 ON f2.user_id2 = u2.user_id
      WHERE u1.user_id < u2.user_id
        -- not already friends (in either direction)
        AND NOT EXISTS (
          SELECT 1 FROM Friendship f3
          WHERE (f3.user_id1 = u1.user_id AND f3.user_id2 = u2.user_id)
             OR (f3.user_id1 = u2.user_id AND f3.user_id2 = u1.user_id)
        )
      GROUP BY u1.user_id, u2.user_id
      HAVING COUNT(DISTINCT f1.user_id2) = 1;
    )SQL";

    sqlite::Statement stmt(conn, sql);
    while (stmt.step() == SQLITE_ROW) {
      // again, only to demonstrate query execution
      std::string u1 = stmt.column_text(0);
      std::string u2 = stmt.column_text(1);
      int mutual_count = stmt.column_int(2);
      (void)u1;
      (void)u2;
      (void)mutual_count;
    }
  }

  // 4) Count friends per user and identify most connected users (aggregation).
  {
    const char* sql = R"SQL(
      SELECT u.user_id,
             u.username,
             COUNT(f.user_id2) AS friend_count
      FROM User u
      LEFT JOIN Friendship f ON u.user_id = f.user_id1
      GROUP BY u.user_id, u.username
      ORDER BY friend_count DESC, u.user_id ASC;
    )SQL";

    sqlite::Statement stmt(conn, sql);
    while (stmt.step() == SQLITE_ROW) {
      int user_id = stmt.column_int(0);
      std::string username = stmt.column_text(1);
      int friend_count = stmt.column_int(2);
      (void)user_id;
      (void)username;
      (void)friend_count;
    }
  }

  // 5) Users in the same city who are not yet friends (recommendation).
  // For this example, all cities are NULL unless the database was pre-populated
  // with additional data, but the query structure demonstrates the pattern.
  {
    const char* sql = R"SQL(
      SELECT u1.username AS user1_name,
             u2.username AS user2_name,
             u1.city
      FROM User u1
      JOIN User u2
        ON u1.city IS NOT NULL
       AND u1.city = u2.city
       AND u1.user_id < u2.user_id
      WHERE NOT EXISTS (
        SELECT 1 FROM Friendship f
        WHERE (f.user_id1 = u1.user_id AND f.user_id2 = u2.user_id)
           OR (f.user_id1 = u2.user_id AND f.user_id2 = u1.user_id)
      );
    )SQL";

    sqlite::Statement stmt(conn, sql);
    while (stmt.step() == SQLITE_ROW) {
      std::string u1 = stmt.column_text(0);
      std::string u2 = stmt.column_text(1);
      std::string city = stmt.column_text(2);
      (void)u1;
      (void)u2;
      (void)city;
    }
  }

  // Return mutual-friend connections as the main analysis result
  return result;
}

}  // namespace analyze_social_network

