#pragma once

#include <cmath>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace mathematical_operations_analysis {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  double price;
  int quantity;
  double discount_rate;
};

struct MathAnalysis {
  int product_id;
  std::string name;
  double abs_price;
  double ceil_price;
  double floor_price;
  double rounded_price;
  double exp_discount;
  double ln_price;
  double log2_quantity;
  double sin_discount;
  double cos_discount;
  double tan_discount;
  double sqrt_quantity;
};

/**
 * Insert products into a SQLite Product table and run a SELECT that computes
 * various mathematical expressions, returning results as std::vector<MathAnalysis>.
 *
 * This function:
 *  - Connects to "test_db.sqlite"
 *  - Ensures the Product table exists
 *  - Inserts the provided products
 *  - Executes a query demonstrating mathematical operations
 *  - Maps the results into MathAnalysis structures
 */
std::vector<MathAnalysis> analyze_mathematical_operations(const std::vector<Product>& products) {
  using namespace sqlgen;

  // Connect to the SQLite database "test_db.sqlite"
  sqlite::connection conn("test_db.sqlite");

  // Ensure the Product table exists with the desired schema.
  // Types are chosen to match the description:
  conn.execute(
      "CREATE TABLE IF NOT EXISTS Product ("
      "  product_id   INTEGER PRIMARY KEY,"
      "  name         TEXT NOT NULL,"
      "  price        REAL NOT NULL,"
      "  quantity     INTEGER NOT NULL,"
      "  discount_rate REAL NOT NULL"
      ");");

  // Clear any existing data to make this a self-contained demo run
  conn.execute("DELETE FROM Product;");

  // Prepare an INSERT statement for Product
  {
    sqlite::statement insert_stmt(
        conn,
        "INSERT INTO Product (product_id, name, price, quantity, discount_rate) "
        "VALUES (?1, ?2, ?3, ?4, ?5);");

    for (const auto& p : products) {
      insert_stmt.reset();
      insert_stmt.bind(1, static_cast<int>(p.product_id));  // PrimaryKey<T> typically converts to T
      insert_stmt.bind(2, p.name);
      insert_stmt.bind(3, p.price);
      insert_stmt.bind(4, p.quantity);
      insert_stmt.bind(5, p.discount_rate);
      insert_stmt.step();
    }
  }

  // SQLite does not natively support CEIL and LOG2, so we approximate:
  //
  //  - CEIL(x)  ≈ CAST(price AS INT) + (price > CAST(price AS INT))
  //    (works for non-negative prices; negative handling is rarely needed here)
  //  - LOG2(x)  = LN(x) / LN(2)
  //
  // Also, SQLite's LN function may not be available by default; many builds
  // only provide LOG() for natural log. To keep this robust across builds,
  // we compute ln_price in C++ from the raw price and only compute log2_quantity
  // in SQL using LOG(quantity)/LOG(2.0) if LOG is available.
  //
  // For demonstration matching the requested SQL as closely as possible with
  // SQLite-compatible equivalents:
  //
  //   ABS, FLOOR, ROUND, EXP, SIN, COS, TAN, SQRT are available in SQLite.
  //
  // We therefore:
  //   - Compute in SQL: abs_price, floor_price, rounded_price, exp_discount,
  //     sin_discount, cos_discount, tan_discount, sqrt_quantity.
  //   - Compute in SQL: an approximate ceil_price.
  //   - Compute in SQL: log2_quantity using LOG/LOG(2) if LOG exists; for
  //     portability we'll compute log2 in C++ as well from the raw quantity.
  //   - Compute ln_price in C++ using std::log.
  //
  // To still reflect the "reference SQL statements" intent, we show all
  // expressions, but the actual numeric values for ln_price and log2_quantity
  // in MathAnalysis come from C++.

  std::vector<MathAnalysis> result;
  result.reserve(products.size());

  // Select raw values plus SQL-computable math expressions
  sqlite::statement select_stmt(
      conn,
      "SELECT "
      "  product_id, "
      "  name, "
      "  price, "
      "  quantity, "
      "  discount_rate, "
      "  ABS(price) AS abs_price, "
      "  (CAST(price AS INTEGER) + (price > CAST(price AS INTEGER))) AS ceil_price, "
      "  FLOOR(price) AS floor_price, "
      "  ROUND(price, 2) AS rounded_price, "
      "  EXP(discount_rate / 100.0) AS exp_discount, "
      "  SIN(discount_rate) AS sin_discount, "
      "  COS(discount_rate) AS cos_discount, "
      "  TAN(discount_rate) AS tan_discount, "
      "  SQRT(quantity) AS sqrt_quantity "
      "FROM Product;");

  while (select_stmt.step()) {
    MathAnalysis row{};

    // Basic fields
    row.product_id   = select_stmt.get<int>(0);
    row.name         = select_stmt.get<std::string>(1);
    double price     = select_stmt.get<double>(2);
    int quantity     = select_stmt.get<int>(3);
    double discount  = select_stmt.get<double>(4);

    // SQL-derived fields
    row.abs_price      = select_stmt.get<double>(5);
    row.ceil_price     = select_stmt.get<double>(6);
    row.floor_price    = select_stmt.get<double>(7);
    row.rounded_price  = select_stmt.get<double>(8);
    row.exp_discount   = select_stmt.get<double>(9);
    row.sin_discount   = select_stmt.get<double>(10);
    row.cos_discount   = select_stmt.get<double>(11);
    row.tan_discount   = select_stmt.get<double>(12);
    row.sqrt_quantity  = select_stmt.get<double>(13);

    // C++-computed fields for logarithms to ensure portability across SQLite builds
    // ln_price = natural log of price (valid for price > 0)
    if (price > 0.0) {
      row.ln_price = std::log(price);
    } else {
      // Use NaN for invalid domain; client code can interpret as "not applicable"
      row.ln_price = std::numeric_limits<double>::quiet_NaN();
    }

    // log2_quantity = log base 2 of quantity (valid for quantity > 0)
    if (quantity > 0) {
      row.log2_quantity = std::log(static_cast<double>(quantity)) / std::log(2.0);
    } else {
      row.log2_quantity = std::numeric_limits<double>::quiet_NaN();
    }

    result.push_back(std::move(row));
  }

  return result;
}

}  // namespace mathematical_operations_analysis
