/**
 * description: replace_text_in_notes.
 * This function demonstrates how to replace text in notes using sqlgen update API.
 * It replaces all occurrences of "foo" with "bar" in the content column of the Note table.
 * Returns: std::vector<UpdatedNote>.
 */
std::vector<UpdatedNote> replace_text_in_notes() {
  using namespace sqlgen;

  // Create a connection to the SQLite database "test_db.sqlite"
  sqlite::connection conn{"test_db.sqlite"};

  // Create a mapper for the Notes table
  auto notes_mapper = make_mapper<Note>(
      "Notes",
      &Note::note_id, column("note_id"),
      &Note::content, column("content"));

  // We'll store and return the updated notes for verification
  std::vector<UpdatedNote> updated_notes;

  // Select notes whose content actually contains "foo"
  // so we don't touch rows unnecessarily.
  auto notes_with_foo = notes_mapper.select(conn)
                            .where(like(&Note::content, "%foo%"))
                            .execute();

  // For each matching note, replace "foo" with "bar" in C++,
  // update the row via sqlgen, and collect the updated view.
  for (auto &note : notes_with_foo) {
    std::string new_content = note.content;
    const std::string from = "foo";
    const std::string to   = "bar";

    // Replace all occurrences of "foo" with "bar" in the content string
    std::size_t pos = 0;
    while ((pos = new_content.find(from, pos)) != std::string::npos) {
      new_content.replace(pos, from.size(), to);
      pos += to.size();
    }

    // Only issue an UPDATE if something actually changed
    if (new_content != note.content) {
      note.content = new_content;

      // Use sqlgen's update API to persist the modified row
      notes_mapper.update(conn, note);

      // Collect an UpdatedNote for verification
      updated_notes.push_back(UpdatedNote{
          note.note_id,
          new_content
      });
    }
  }

  return updated_notes;
}

}  // namespace replace_text_in_notes
