namespace inventory_bulk_write_and_read {

struct Inventory {
  sqlgen::PrimaryKey<int> item_id;
  std::string name;
  int quantity;
  std::string location;
};

// Tell sqlgen how Inventory maps to the Inventory table
SQLGEN_DECLARE_TABLE(
    Inventory,
    "Inventory",
    (item_id, "item_id"),
    (name, "name"),
    (quantity, "quantity"),
    (location, "location"))

/**
 * description: inventory_bulk_write_and_read.
 * This function demonstrates how to perform bulk write and read operations on an inventory table.
 * It assumes the Inventory table already exists in test_db.sqlite.
 * It writes the given items to the table using a single transaction (bulk insert),
 * then reads back the items with quantity > 50, ordered by quantity in descending order,
 * and returns true if at least one item is found.
 * Returns: bool.
 */
bool inventory_bulk_write_and_read(const std::vector<Inventory>& items) {
  using namespace sqlgen;

  // Open (or create) the SQLite database
  sqlite::connection conn("test_db.sqlite");

  // Create a context for ORM-style operations
  context ctx(conn);

  // Ensure the mapping for Inventory is registered
  ctx.attach<Inventory>();

  // Bulk write: insert all provided items in a single transaction
  {
    transaction tx(ctx);
    for (const auto& item : items) {
      ctx.insert(item);
    }
    tx.commit();
  }

  // Read items where quantity > 50 and order by quantity DESC
  auto results = ctx.select<Inventory>()
                       .where(field<&Inventory::quantity>() > 50)
                       .order_by(desc(field<&Inventory::quantity>()))
                       .exec();

  // Return true if at least one matching item exists
  return !results.empty();
}

}  // namespace inventory_bulk_write_and_read
