#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace cascade_delete_demo {

struct Parent {
  sqlgen::PrimaryKey<int> parent_id;
  std::string name;
};

struct Child {
  sqlgen::PrimaryKey<int> child_id;
  sqlgen::ForeignKey<int, Parent, "parent_id"> parent_id;
  std::string note;
};

/**
 * Demonstrates cascade delete behavior in SQLite using foreign key constraints.
 * Returns: bool indicating whether child rows were automatically deleted
 * after deleting the corresponding parent row.
 */
bool cascade_delete_demo() {
  using namespace sqlgen;

  // Connect to SQLite database "test_db.sqlite"
  sqlite::Connection conn("test_db.sqlite");

  // Ensure foreign keys are enabled in SQLite
  conn.execute("PRAGMA foreign_keys = ON;");

  // Get a database object for template-based operations
  auto db = make_database(conn);

  // Recreate tables to have a clean test state and proper constraints
  db.drop_table_if_exists<Child>();
  db.drop_table_if_exists<Parent>();
  db.create_table<Parent>();
  db.create_table<Child>();

  // Insert one parent and one child referencing that parent
  Parent p{PrimaryKey<int>{1}, "parent1"};
  db.insert(p);

  Child c{PrimaryKey<int>{1}, ForeignKey<int, Parent, "parent_id">{1}, "note1"};
  db.insert(c);

  // Verify that one child exists before deletion
  {
    auto children_before =
        db.select<Child>().where(&Child::parent_id == 1).all();
    if (children_before.size() != 1) {
      return false;
    }
  }

  // Delete parent row
  db.remove<Parent>().where(&Parent::parent_id == 1).execute();

  // Check if corresponding child rows were automatically deleted
  auto children_after =
      db.select<Child>().where(&Child::parent_id == 1).all();

  return children_after.empty();
}

}  // namespace cascade_delete_demo
