namespace update_set_operations {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
  std::string status;
};

/**
 * description: update_set_operations.
 * This function demonstrates how to use set operations in update statements using sqlgen write API.
 * It returns true if the update operations are successful, and false otherwise.
 * Returns: bool.
 */
bool update_set_operations() {
  try {
    // Open (or create) the SQLite database
    sqlgen::sqlite::connection db("test_db.sqlite");

    // Create the Account table if it does not exist
    db.execute(R"SQL(
      CREATE TABLE IF NOT EXISTS Account (
        account_id INTEGER PRIMARY KEY,
        balance REAL NOT NULL,
        status TEXT NOT NULL
      );
    )SQL");

    // Create a relation for the Account table
    auto accounts = sqlgen::make_relation<Account>("Account")
                      .field(&Account::account_id, "account_id")
                      .field(&Account::balance, "balance")
                      .field(&Account::status, "status");

    // Clear existing rows to have a deterministic state for the demo
    db.execute("DELETE FROM Account;");

    // Insert some sample accounts
    {
      auto ins = sqlgen::insert_into(accounts)
                   .columns(&Account::account_id, &Account::balance, &Account::status)
                   .values(1, 100.0, std::string("active"))
                   .values(2, -50.0, std::string("active"))
                   .values(3, 300.0, std::string("inactive"));

      if (db.execute(ins) < 0) {
        return false;
      }
    }

    // 1) Update balance for a specific account using set(...)
    {
      auto upd = sqlgen::update(accounts)
                   .set(&Account::balance, 200.0)
                   .where(&Account::account_id == 1);

