```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <string>

namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier
 * and the name of a product, if any. Demonstrates a FULL JOIN between suppliers and
 * products using SQLite (which lacks native FULL OUTER JOIN) by combining a LEFT JOIN
 * and a RIGHT JOIN (simulated with a LEFT JOIN in the opposite direction and NULL filter).
 */
std::vector<SupProd> full_join_suppliers_products() {
  using namespace sqlgen;

  // Open (or create) SQLite database
  sqlite::database db("test_db.sqlite");

  // Create table descriptors for sqlgen
  auto suppliers = make_table<Supplier>("Supplier");
  auto products  = make_table<Product>("Product");

  // Build a query that emulates FULL OUTER JOIN via UNION of:
  // 1) LEFT JOIN Supplier -> Product
  // 2) LEFT JOIN Product  -> Supplier (only rows where Supplier side is NULL)
  //
  // Schema:
  //   Supplier(supplier_id, name)
  //   Product(product_id, supplier_id, name)
  //
  // The resulting columns:
  //   supplier_name, product_name (product_name may be NULL)

  using Row = std::tuple<std::optional<std::string>, std::optional<std::string>>;

  // First part: all suppliers and their products (if any)
  auto left_join_query =
      select(suppliers.name, products.name)
          .from(suppliers)
          .left_join(products, suppliers.supplier_id == products.supplier_id);

  // Second part: products that have no matching supplier (right-join simulation)
  auto right_only_query =
      select(suppliers.name, products.name)
          .from(products)
          .left_join(suppliers, products.supplier_id == suppliers.supplier_id)
          .where(is_null(suppliers.supplier_id));

  // Combine them via UNION ALL to emulate FULL OUTER JOIN
  auto full_join_query = union_all(left_join_query, right_only_query);

  std::vector<Row> rows;
  execute(db, full_join_query, rows);

  std::vector<SupProd> result;
  result.reserve(rows.size());

  for (auto &r : rows) {
    SupProd sp{};
    // supplier_name: if NULL (can happen for product-only rows), use empty string
    // since SupProd::supplier_name is not optional.
    sp.supplier_name = std::get<0>(r).value_or(std::string{});
    sp.product_name  = std::get<1>(r);
    result.push_back(std::move(sp));
  }

  return result;
}

}  // namespace full_join_suppliers_products
```

