```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <string>

namespace analyze_department_employees {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string department_name;
  std::string location;
};

struct Employee {
  sqlgen::PrimaryKey<int> employee_id;
  int department_id;
  std::string first_name;
  std::string last_name;
  double salary;
};

struct JoinResult {
  std::optional<std::string> department_name;
  std::optional<std::string> first_name;
  std::optional<std::string> last_name;
  std::optional<double> salary;
};

struct JoinAnalysis {
  std::vector<JoinResult> inner_join_results;
  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

/**
 * analyze_department_employees
 * Provides data-join analysis between Department and Employee input collections by
 * creating SQL tables in the SQLite database "test_db.sqlite", inserting the
 * provided rows, and executing a variety of join queries to produce join-output
 * samples.
 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts,
                                               const std::vector<Employee>& emps) {
  using namespace sqlgen;

  // Connect to SQLite database "test_db.sqlite"
  sqlite::Connection conn("test_db.sqlite");

  // Create ORM mapping for Department and Employee
  auto orm = makeOrm(conn, "Department", "Employee");

  // Ensure tables exist (idempotent create)
  orm.createTable<Department>();
  orm.createTable<Employee>();

  // Clear existing rows to make analysis deterministic for this call
  orm.removeAll<Employee>();
  orm.removeAll<Department>();

  // Insert provided rows
  for (const auto& d : depts) {
    orm.insert(d);
  }
  for (const auto& e : emps) {
    orm.insert(e);
  }

  JoinAnalysis analysis;

  // Helper lambda to run a join query and map it into JoinResult vector
  auto run_join_query = [&](const std::string& sql) {
    std::vector<JoinResult> results;

    conn.exec(
        sql,
        [&](sqlite::Statement& stmt) {
          JoinResult jr;

          // Column 0: department_name (nullable)
          if (stmt.columnType(0) == SQLITE_NULL) {
            jr.department_name = std::nullopt;
          } else {
            jr.department_name = stmt.get<std::string>(0);
          }

          // Column 1: first_name (nullable)
          if (stmt.columnType(1) == SQLITE_NULL) {
            jr.first_name = std::nullopt;
          } else {
            jr.first_name = stmt.get<std::string>(1);
          }

          // Column 2: last_name (nullable)
          if (stmt.columnType(2) == SQLITE_NULL) {
            jr.last_name = std::nullopt;
          } else {
            jr.last_name = stmt.get<std::string>(2);
          }

          // Column 3: salary (nullable)
          if (stmt.columnType(3) == SQLITE_NULL) {
            jr.salary = std::nullopt;
          } else {
            jr.salary = stmt.get<double>(3);
          }

          results.push_back(std::move(jr));
        });

    return results;
  };

  // INNER JOIN: employees that have departments
  const std::string inner_join_sql =
      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Department d "
      "INNER JOIN Employee e ON d.department_id = e.department_id;";

  analysis.inner_join_results = run_join_query(inner_join_sql);

  // LEFT JOIN: all employees, including those without departments
  const std::string left_join_sql =
      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Employee e "
      "LEFT JOIN Department d ON e.department_id = d.department_id;";

  analysis.left_join_results = run_join_query(left_join_sql);

  // RIGHT JOIN emulation in SQLite:
  // All departments, plus matching employees
  // (SQLite has no RIGHT JOIN; emulate by swapping tables in a LEFT JOIN)
  const std::string right_join_sql =
      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Department d "
      "LEFT JOIN Employee e ON e.department_id = d.department_id;";

  analysis.right_join_results = run_join_query(right_join_sql);

  // FULL OUTER JOIN emulation in SQLite:
  // UNION of LEFT JOIN (employees -> departments) and LEFT JOIN
  // (departments -> employees) with an anti-join to avoid duplicates.
  const std::string full_join_sql =
      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Employee e "
      "LEFT JOIN Department d ON e.department_id = d.department_id "
      "UNION "
      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Department d "
      "LEFT JOIN Employee e ON e.department_id = d.department_id "
      "WHERE e.employee_id IS NULL;";

  analysis.full_join_results = run_join_query(full_join_sql);

  return analysis;
}

}  // namespace analyze_department_employees
```

