  int stock;
};

bool update_inventory_stock(const std::unordered_map<int, int>& received) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto conn_res = sqlite::connect("test_db.sqlite");
  if (!conn_res) return false;
  auto& conn = conn_res.value();

  // Ensure Product table exists (no-op if already created)
  auto create_res = create_table<Product>(conn);
  if (!create_res) return false;

  // Begin single transaction for all updates
  auto txn_res = begin_transaction(conn);
  if (!txn_res) return false;
  auto& txn = txn_res.value();

  // Prepare a parameterized UPDATE statement
  // UPDATE Product SET stock = stock + ? WHERE product_id = ?;
  auto stmt_res = prepare(
      txn,
      "UPDATE Product SET stock = stock + ? WHERE product_id = ?;"_sql
  );
  if (!stmt_res) {
    // If we cannot prepare the statement, roll back the transaction
    (void)rollback(txn);
    return false;
  }
  auto& stmt = stmt_res.value();

  // Execute the UPDATE for each product in the input map
  for (const auto& [pid, qty] : received) {
    // Bind parameters (position indices assumed 1-based)
    auto bind_res = bind(stmt, qty, pid);
    if (!bind_res) {
      (void)rollback(txn);
      return false;
    }

    auto exec_res = exec(stmt);
    if (!exec_res) {
      (void)rollback(txn);
      return false;
    }

    // Reset statement to reuse for the next iteration
    auto reset_res = reset(stmt);
    if (!reset_res) {
      (void)rollback(txn);
      return false;
    }
  }

  // Commit transaction if all updates succeeded
  auto commit_res = commit(txn);
  if (!commit_res) {
    (void)rollback(txn);
    return false;
  }

  return true;
}

