std::vector<OrderSummary> create_view_order_summary() {
  // Connect to SQLite database "test_db.sqlite"
  sqlgen::sqlite::Database db("test_db.sqlite");

  // Create the view (DROP first in case it already exists)
  const char* drop_view_sql = "DROP VIEW IF EXISTS OrderSummaryView;";
  db.exec(drop_view_sql);

  const char* create_view_sql =
      "CREATE VIEW OrderSummaryView AS "
      "SELECT o.order_id, o.customer, "
      "       SUM(oi.unit_price * oi.quantity) AS total "
      "FROM \"Order\" o "
      "INNER JOIN OrderItem oi ON o.order_id = oi.order_id "
      "GROUP BY o.order_id, o.customer;";

