  auto stmt = db.prepare(
      sqlgen::select_from<OrderSummary>()
          .columns(&OrderSummary::order_id,
                   &OrderSummary::customer,
                   &OrderSummary::total));

  std::vector<OrderSummary> results;
  while (stmt.step()) {
    results.push_back(stmt.get<OrderSummary>());
  }

  return results;
