  sqlgen::PrimaryKey<int> id;
  int user_id;
  std::string title;
};

/**
 * This function demonstrates a LEFT JOIN.
 * Returns: std::string.
 */
inline std::string left_join_explicit() {
  using namespace sqlgen;
  using sqlite::make_sqlite_dialect;

  // Define table aliases for clarity.
  auto u = table<User>("users");
  auto p = table<Post>("posts");

  // Build a LEFT JOIN query:
  // SELECT users.id, users.name, posts.id, posts.user_id, posts.title
  // FROM users
  // LEFT JOIN posts ON users.id = posts.user_id;
  auto q = select(u.id, u.name, p.id, p.user_id, p.title)
             .from(u)
             .left_join(p, u.id == p.user_id);

  // Generate and return the SQL string using the SQLite dialect.
  return to_sql(q, make_sqlite_dialect());
}

}  // namespace left_join_explicit
