#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <string>

namespace weekday_sales_analysis {

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> sale_time;
};

struct WeekdayStats {
  int weekday;         // 0 = Sunday, 1 = Monday, ... (SQLite strftime('%w', ...) convention)
  int total_quantity;
};

/**
 * Description: This function analyzes sales data to calculate total quantity sold for each weekday.
 * Returns: std::vector<WeekdayStats>.
 */
std::vector<WeekdayStats> weekday_sales_analysis() {
  using namespace sqlgen;
  using namespace sqlgen::sqlite;

  // Open SQLite database "test_db.sqlite"
  auto db = Database::open("test_db.sqlite");

  // Define a lightweight aggregate mapping that matches the SQL result
  struct WeekdayAgg {
    int weekday;
    int total_quantity;
  };

  // Perform the aggregation:
  // - Extract weekday using SQLite's strftime('%w', sale_time)
  // - Group by weekday
  auto results = db.select<WeekdayAgg>()
      .from<Sales>()
      .columns(
        // Cast strftime('%w', sale_time) to INT for mapping into WeekdayAgg::weekday
        expr<int>("CAST(strftime('%w', sale_time) AS INTEGER)").as(&WeekdayAgg::weekday),
        expr<int>("SUM(quantity)").as(&WeekdayAgg::total_quantity)
      )
      .group_by(expr("strftime('%w', sale_time)"))
      .execute();

  // Convert to the exposed WeekdayStats type
  std::vector<WeekdayStats> stats;
  stats.reserve(results.size());
  for (const auto& row : results) {
    WeekdayStats s;
    s.weekday = row.weekday;
    s.total_quantity = row.total_quantity;
    stats.push_back(s);
  }

  return stats;
}

}  // namespace weekday_sales_analysis
```

