```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace project_time_tracking {

struct Project {
  sqlgen::PrimaryKey<int> project_id;
  std::string name;
};

struct TimeLog {
  sqlgen::PrimaryKey<int> log_id;
  int project_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> start_time;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> end_time;
};

struct TimeMetrics {
  sqlgen::PrimaryKey<int> project_id;
  std::string name;
  int day;
  int month;
  int year;
  int hour;
  int minute;
  int second;
  double duration_days;
};

/**
 * Description: This function tracks time metrics for each project, including day, month, year, hour, minute, second, and duration in days.
 * Returns: std::vector<TimeMetrics>.
 */
std::vector<TimeMetrics> project_time_tracking() {
  using namespace sqlgen;

  // Open SQLite connection
  auto conn = sqlite::connection::open("test_db.sqlite");

  // Define a raw result mapping for the query, since the result is an aggregate/join
  struct Row {
    int project_id;
    std::string name;
    int year;
    int week;
    int day;
    int month;
    int hour;
    int minute;
    int second;
    double duration_days;
  };

  // The query:
  // 1. Joins Project and TimeLog
  // 2. Extracts date/time components from start_time
  // 3. Computes days_between(start_time, end_time) (using julianday() diff for SQLite)
  // 4. Groups by project and week (plus the extracted components needed in the result)
  //
  // Week is computed via strftime('%W', start_time) (week of year, 00-53).
  auto stmt = conn.prepare<Row>(R"SQL(
    SELECT
        p.project_id AS project_id,
        p.name       AS name,
        CAST(strftime('%Y', t.start_time) AS INTEGER)             AS year,
        CAST(strftime('%W', t.start_time) AS INTEGER)             AS week,
        CAST(strftime('%d', t.start_time) AS INTEGER)             AS day,
        CAST(strftime('%m', t.start_time) AS INTEGER)             AS month,
        CAST(strftime('%H', t.start_time) AS INTEGER)             AS hour,
        CAST(strftime('%M', t.start_time) AS INTEGER)             AS minute,
        CAST(strftime('%S', t.start_time) AS INTEGER)             AS second,
        SUM(julianday(t.end_time) - julianday(t.start_time))      AS duration_days
    FROM Project p
    INNER JOIN TimeLog t
      ON p.project_id = t.project_id
    GROUP BY
        p.project_id,
        p.name,
        year,
        week,
        day,
        month,
        hour,
        minute,
        second
    ORDER BY
        p.project_id,
        year,
        week,
        day,
        hour,
        minute,
        second
  )SQL");

  std::vector<TimeMetrics> result;
  for (auto &&row : stmt.execute()) {
    TimeMetrics m;
    m.project_id = row.project_id;
    m.name       = row.name;
    m.year       = row.year;
    m.month      = row.month;
    m.day        = row.day;
    m.hour       = row.hour;
    m.minute     = row.minute;
    m.second     = row.second;
    m.duration_days = row.duration_days;
    result.push_back(std::move(m));
  }

  return result;
}

}  // namespace project_time_tracking
```

